search_script.example_code:
// 1. التصفية المسبقة باستخدام البحث القياسي const candidateNotes = api.searchForNotes("#journal");

// 2. تطبيق معايير بحث مخصصة const matchedNotes = candidateNotes .filter(note => note.title.match(/[0-9]{1,2}. ?[0-9]{1,2}. ?[0-9]{4}/));

return matchedNotes;
